const msg = $input.first().json;
const text   = (msg.message?.text || '').trim();
const chatId  = msg.message?.chat?.id;
const firstName = msg.message?.from?.first_name || 'User';

if (!text || !chatId) throw new Error('No text or chatId found in message');

return [{ json: { text, chatId, firstName } }];

const f = $input.first().json;

const errors = [];

const name     = (f['Full name']             || '').trim();
const age      = parseInt(f['Age'])          || 0;
const gender   = (f['Gender']               || '').trim();
const blood    = (f['Blood type']           || '').trim();
const cond     = (f['Medical condition']    || '').trim();
const med      = (f['Medication']           || '').trim();
const insurer  = (f['Insurance provider']   || '').trim();
const admType  = (f['Admission type']       || '').trim();
const result   = (f['Test result']          || '').trim();
const doctor   = (f['Doctor name']          || '').trim();
const hospital = (f['Hospital name']        || '').trim();
const room     = parseInt(f['Room number']) || 0;
const billing  = parseFloat(f['Billing amount (USD)']) || 0;
const admDateRaw = (f['Date of admission']  || '').trim();
const disDateRaw = (f['Date of discharge']  || '').trim();

if (!name)                    errors.push('Full name is required');
if (age < 1 || age > 120)     errors.push('Age must be between 1 and 120');
if (!gender)                  errors.push('Gender is required');
if (!blood)                   errors.push('Blood type is required');
if (!cond)                    errors.push('Medical condition is required');
if (!med)                     errors.push('Medication is required');
if (!insurer)                 errors.push('Insurance provider is required');
if (!admType)                 errors.push('Admission type is required');
if (!result)                  errors.push('Test result is required');
if (!doctor)                  errors.push('Doctor name is required');
if (!hospital)                errors.push('Hospital name is required');
if (room < 101 || room > 500) errors.push('Room number must be between 101 and 500');
if (billing <= 0)             errors.push('Billing amount must be greater than 0');
if (!admDateRaw)              errors.push('Date of admission is required');
if (!disDateRaw)              errors.push('Date of discharge is required');

if (errors.length > 0) throw new Error('Validation failed: ' + errors.join(' | '));

// Safe date parsing — avoids UTC timezone shift
// Handles: "2022-03-15", "2022-03-15T00:00:00.000Z", "03/15/2022", "2022/03/15"
function parseDateParts(raw) {
  const clean = raw.split('T')[0].trim();
  let year, month, day;
  if (clean.includes('-')) {
    [year, month, day] = clean.split('-').map(Number);
  } else if (clean.includes('/')) {
    const parts = clean.split('/').map(Number);
    if (parts[0] > 31) {
      [year, month, day] = parts;
    } else {
      [month, day, year] = parts;
    }
  } else {
    throw new Error('Unrecognized date format: ' + raw);
  }
  if (!year || !month || !day) throw new Error('Could not parse date: ' + raw);
  return { year, month, day };
}

let admParts, disParts;
try {
  admParts = parseDateParts(admDateRaw);
} catch(e) {
  throw new Error('Invalid admission date: ' + admDateRaw + '. Use YYYY-MM-DD format.');
}
try {
  disParts = parseDateParts(disDateRaw);
} catch(e) {
  throw new Error('Invalid discharge date: ' + disDateRaw + '. Use YYYY-MM-DD format.');
}

// Build dateId as integer YYYYMMDD — no timezone conversion
const admDateId = admParts.year * 10000 + admParts.month * 100 + admParts.day;
const disDateId = disParts.year * 10000 + disParts.month * 100 + disParts.day;

// Validate date range — dim_date must cover this range in SQL Server
const DATE_MIN = 20190101;
const DATE_MAX = 20301231;

if (admDateId < DATE_MIN || admDateId > DATE_MAX) {
  throw new Error(
    'Admission date ' + admDateRaw +
    ' is outside the allowed range (2019-01-01 to 2030-12-31).'
  );
}
if (disDateId < DATE_MIN || disDateId > DATE_MAX) {
  throw new Error(
    'Discharge date ' + disDateRaw +
    ' is outside the allowed range (2019-01-01 to 2030-12-31).'
  );
}
if (disDateId < admDateId) {
  throw new Error('Discharge date cannot be before admission date.');
}

// Calculate length of stay in days (no timezone — uses local date constructor)
const admDateObj = new Date(admParts.year, admParts.month - 1, admParts.day);
const disDateObj = new Date(disParts.year, disParts.month - 1, disParts.day);
const lengthOfStay = Math.round((disDateObj - admDateObj) / (1000 * 60 * 60 * 24));

// Format dates as YYYY-MM-DD string for display and SQL
const admDate = admParts.year + '-' +
  String(admParts.month).padStart(2, '0') + '-' +
  String(admParts.day).padStart(2, '0');
const disDate = disParts.year + '-' +
  String(disParts.month).padStart(2, '0') + '-' +
  String(disParts.day).padStart(2, '0');

return [{ json: {
  name, age, gender, blood, cond, med, insurer,
  admType, result, doctor, hospital,
  room, billing, admDate, disDate,
  lengthOfStay, admDateId, disDateId
} }];

const rows = $input.all().map(i => i.json);
const newId = rows[0]?.new_hospitalization_id || 'N/A';
const data  = $('Validate Fields1').first().json;

return [{ json: {
  newId,
  name:    data.name,
  cond:    data.cond,
  insurer: data.insurer,
  admDate: data.admDate,
  billing: data.billing,
  lengthOfStay: data.lengthOfStay
} }];

const err = $input.first().json;
const msg = err.message || err.error || 'Unknown error';
return [{ json: { errorMessage: msg } }];
